package com.arkeomag.pro; import android.content.*;import android.view.*;import android.graphics.*;
public class CalibrationPanel extends View{Paint p=new Paint(1);float x,y,z; public CalibrationPanel(Context c){super(c);} public void set(float a,float b,float cc){x=a;y=b;z=cc;invalidate();} protected void onDraw(Canvas c){int w=getWidth(),h=getHeight();p.setColor(Color.rgb(8,15,28));c.drawRoundRect(0,0,w,h,28,28,p);draw(c,w/4,h/2,"XY",x,y);draw(c,w/2,h/2,"YZ",y,z);draw(c,3*w/4,h/2,"XZ",x,z);}void draw(Canvas c,int cx,int cy,String label,float a,float b){int r=80;p.setStyle(Paint.Style.STROKE);p.setStrokeWidth(5);p.setColor(Color.rgb(0,210,255));c.drawCircle(cx,cy,r,p);p.setStyle(Paint.Style.FILL);p.setColor(Color.rgb(255,220,0));c.drawCircle(cx+Math.max(-r,Math.min(r,a*2)),cy+Math.max(-r,Math.min(r,b*2)),11,p);p.setColor(Color.WHITE);p.setTextAlign(Paint.Align.CENTER);p.setTextSize(25);c.drawText(label,cx,cy+r+35,p);}}
